const mongoose = require('mongoose');

const DENIAL_CODES = [
  'NOT_COVERED',            // service type not in coverage rules
  'LIMIT_EXHAUSTED',        // annual limit used up
  'POLICY_INACTIVE',        // policy not active on date of service
  'NO_COVERAGE_VERSION',    // no PolicyVersion was active on date of service
  'REQUIRES_PRE_AUTH'       // pre-authorization required but not obtained
];

const TRIGGERING_EVENTS = [
  'INITIAL_SUBMISSION',
  'APPEAL',
  'RULE_CORRECTION',
  'ADMIN_OVERRIDE'
];

const claimDecisionSchema = new mongoose.Schema({
  claimId: { type: mongoose.Schema.Types.ObjectId, ref: 'Claim', required: true },
  claimItemId: { type: mongoose.Schema.Types.ObjectId, required: true },
  // Monotonically increasing within a claimItemId — version 1 is always the original decision
  versionNumber: { type: Number, required: true, default: 1 },
  // Which PolicyVersion's rules were applied — immutable audit link
  policyVersionId: { type: mongoose.Schema.Types.ObjectId, ref: 'PolicyVersion' },
  adjudicatedAt: { type: Date, default: Date.now },
  billedAmount: { type: Number, required: true },
  approvedAmount: { type: Number, default: 0 },
  coveredPercent: { type: Number },
  deductibleApplied: { type: Number, default: 0 },
  denialCode: { type: String, enum: DENIAL_CODES, default: null },
  denialReason: { type: String },
  // Human-readable explanation sent to the member
  explanation: { type: String, required: true },
  // Set when this decision is superseded by a reprocess or appeal
  supersededBy: { type: mongoose.Schema.Types.ObjectId, ref: 'ClaimDecision', default: null },
  triggeringEvent: { type: String, enum: TRIGGERING_EVENTS, default: 'INITIAL_SUBMISSION' }
}, { timestamps: true });

claimDecisionSchema.index({ claimId: 1, claimItemId: 1 });
claimDecisionSchema.index({ claimId: 1, supersededBy: 1 });

module.exports = mongoose.model('ClaimDecision', claimDecisionSchema);
```

## PolicyVersion.js

```javascript
const mongoose = require('mongoose');

const BENEFIT_CATEGORIES = ['MEDICAL', 'DENTAL', 'VISION', 'MENTAL_HEALTH', 'PRESCRIPTION'];

const coverageRuleSchema = new mongoose.Schema({
  benefitCategory: { type: String, required: true, enum: BENEFIT_CATEGORIES },
  // Empty array means rule applies to all service types in this category
  serviceTypes: [String],
  coveredPercent: { type: Number, required: true, min: 0, max: 100 },
  annualLimit: { type: Number, required: true, min: 0 },
  deductible: { type: Number, default: 0, min: 0 },
  requiresPreAuth: { type: Boolean, default: false }
}, { _id: false });

const policyVersionSchema = new mongoose.Schema({
  policyId: { type: mongoose.Schema.Types.ObjectId, ref: 'Policy', required: true },
  versionNumber: { type: Number, required: true },
  effectiveFrom: { type: Date, required: true },
  // null = currently active version
  effectiveTo: { type: Date, default: null },
  coverageRules: { type: [coverageRuleSchema], required: true },
  changeReason: { type: String },
  // true = this version's rules apply retroactively to claims with dateOfService before effectiveFrom
  isRetroactive: { type: Boolean, default: false }
}, { timestamps: true });

policyVersionSchema.index({ policyId: 1, effectiveFrom: -1 });
// Enforce at most one active version (no effectiveTo) per policy
policyVersionSchema.index(
  { policyId: 1, effectiveTo: 1 },
  { unique: true, partialFilterExpression: { effectiveTo: null } }
);

module.exports = mongoose.model('PolicyVersion', policyVersionSchema);
```

## limit.service.js

```javascript
const LimitLedger = require('../models/LimitLedger');

// All limit operations execute inside a MongoDB session/transaction passed by the caller.
// The $push to the same document serializes under write-write conflict detection,
// so two concurrent adjudications can't both read "enough capacity" and both approve.

function calendarYearPeriod(date) {
  const d = new Date(date);
  return {
    periodStart: new Date(d.getFullYear(), 0, 1),
    periodEnd: new Date(d.getFullYear(), 11, 31, 23, 59, 59, 999)
  };
}

async function getOrCreateLedger(policyId, memberId, benefitCategory, date, session) {
  const { periodStart, periodEnd } = calendarYearPeriod(date);

  let ledger = await LimitLedger.findOne(
    { policyId, benefitCategory, periodStart },
    null,
    { session }
  );

  if (!ledger) {
    [ledger] = await LimitLedger.create(
      [{ policyId, memberId, benefitCategory, periodStart, periodEnd, entries: [] }],
      { session }
    );
  }

  return ledger;
}

async function getAvailable(policyId, memberId, benefitCategory, date, annualLimit, session) {
  const { periodStart } = calendarYearPeriod(date);
  const ledger = await LimitLedger.findOne(
    { policyId, benefitCategory, periodStart },
    null,
    session ? { session } : {}
  );
  if (!ledger) return annualLimit;
  return ledger.computeAvailable(annualLimit);
}

// Atomically consume capacity for an approved claim item.
// Returns the actual amount consumed (may be less than requested if near limit).
async function consume(policyId, memberId, benefitCategory, date, claimId, claimItemId, amount, annualLimit, session) {
  const ledger = await getOrCreateLedger(policyId, memberId, benefitCategory, date, session);
  const available = ledger.computeAvailable(annualLimit);

  if (available <= 0) return 0;

  const consumeAmount = Math.min(amount, available);

  await LimitLedger.findByIdAndUpdate(
    ledger._id,
    { $push: { entries: { claimId, claimItemId, type: 'CONSUME', amount: consumeAmount } } },
    { session }
  );

  return consumeAmount;
}

// Release previously consumed capacity (reprocessing or reversal).
async function release(policyId, memberId, benefitCategory, date, claimId, claimItemId, amount, session) {
  const { periodStart } = calendarYearPeriod(date);
  const ledger = await LimitLedger.findOne({ policyId, benefitCategory, periodStart }, null, { session });
  if (!ledger) return;

  await LimitLedger.findByIdAndUpdate(
    ledger._id,
    { $push: { entries: { claimId, claimItemId, type: 'RELEASE', amount } } },
    { session }
  );
}

// Release all CONSUME entries for a claim (used during reprocessing).
async function releaseAllForClaim(policyId, memberId, date, claimId, itemConsumptions, session) {
  for (const { benefitCategory, claimItemId, amount } of itemConsumptions) {
    await release(policyId, memberId, benefitCategory, date, claimId, claimItemId, amount, session);
  }
}

module.exports = { getAvailable, consume, release, releaseAllForClaim, calendarYearPeriod };
```

